import jwt
from jwt import ExpiredSignatureError, InvalidTokenError
from pycryptodome import encryption, x509, utility
from pycryptodome.util.encoders import base64

def verify_jwt(token, key, algorithm='HS256'):
    try:
        if algorithm == 'HS256':
            encoded_key = base64.b64encode(key)
        elif algorithm == 'RS256':
            cert = x509.load_pem_x509_certificate(key)
            public_key = encryption.publickey.rsa.RSAPubKey()
            public_key.importFromPublicKey(cert)
        else:
            raise ValueError(f"Unsupported algorithm: {algorithm}")

        claims = jwt.decode(token, key=encoded_key, algorithms=[algorithm])
        return claims
    except (ExpiredSignatureError, InvalidTokenError):
        return None

def extract_payload(token):
    try:
        claims = verify_jwt(token, None)
        if claims is not None:
            return claims['payload']
    except Exception as e:
        print(f"Error while extracting payload: {e}")
        return None